sql:
SELECT dataset_id, year
FROM datasets
WHERE factor = 'Male';

SELECT datasets.dataset_id, factors.factor
FROM datasets
INNER JOIN factors ON datasets.dataset_id = factors.dataset_id;

SELECT d.factor, d.year, ar.age_range, ar.count
FROM datasets d
INNER JOIN age_ranges ar ON d.dataset_id = ar.dataset_id AND d.dataset_id = 1;

external_knowledge:
- 'Desired Year', 'Desired Factor', and 'Desired Dep06' are placeholders for actual year, demographic factor, and geographic region values; 
- Demographic factors include 'Male' and 'Female';
- Geographic regions are identified by codes such as 'Dep06'.

sql:
SELECT datasets.*, age_ranges.*
FROM datasets
JOIN age_ranges ON datasets.dataset_id = age_ranges.dataset_id;

SELECT dataset_id, age_range, count
FROM age_ranges
WHERE count < 10000;
